steps.script:
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
const normalize = (value) => (value || '').replace(/\u00a0/g, ' ').replace(/\s+/g, ' ').trim();
const normalizeUrl = (raw) => {
  if (!raw) return '';
  try {
    return new URL(raw, window.location.origin).toString();
  } catch {
    return String(raw);
  }
};
const unique = (items) => Array.from(new Set((items || []).filter(Boolean)));
const isVisible = (node) => {
  if (!(node instanceof Element)) return false;
  const style = window.getComputedStyle(node);
  if (style.display === 'none' || style.visibility === 'hidden' || Number(style.opacity || '1') === 0) return false;
  const rect = node.getBoundingClientRect();
  return rect.width > 0 && rect.height > 0;
};
const waitForArticleSurface = async () => {
  const deadline = Date.now() + 12000;
  while (Date.now() < deadline) {
    const root = document.querySelector('main article') || document.querySelector('article') || document.querySelector('main [data-testid="article"]') || document.querySelector('main');
    const textLength = normalize(root?.textContent || '').length;
    if (root && textLength > 300) return root;
    await sleep(350);
  }
  return document.querySelector('main article') || document.querySelector('article') || document.querySelector('main');
};
const scoreNode = (node) => {
  const text = normalize(node?.textContent || '');
  if (!text) return -Infinity;
  const paragraphs = Array.from(node.querySelectorAll('p')).filter((item) => normalize(item.textContent || '').length >= 40).length;
  const headings = node.querySelectorAll('h1, h2, h3').length;
  const images = node.querySelectorAll('img').length;
  let score = text.length * 0.02 + paragraphs * 50 + headings * 15 + images * 8;
  const attrText = normalize([node.id || '', node.className || '', node.getAttribute('data-testid') || '', node.getAttribute('role') || ''].join(' ')).toLowerCase();
  if (/article|content|body|story|post|main/.test(attrText)) score += 80;
  if (/reply|toolbar|button|nav|header|footer|sidebar|related|share|menu|modal|popup/.test(attrText)) score -= 120;
  if (node.tagName.toLowerCase() === 'article') score += 180;
  if (node.tagName.toLowerCase() === 'main') score += 120;
  return score;
};
const articleRoot = await waitForArticleSurface();
const candidates = unique([articleRoot, document.querySelector('main article'), document.querySelector('article'), document.querySelector('main')]).filter(Boolean);
let contentRoot = null;
let bestScore = -Infinity;
for (const candidate of candidates) {
  if (!(candidate instanceof Element)) continue;
  const scoped = [candidate, ...Array.from(candidate.querySelectorAll('article, section, div'))].slice(0, 80);
  for (const node of scoped) {
    if (!(node instanceof Element) || !isVisible(node)) continue;
    const score = scoreNode(node);
    if (score > bestScore) {
      bestScore = score;
      contentRoot = node;
    }
  }
}
const root = contentRoot || articleRoot || document.querySelector('main') || document.body;
const canonicalUrl = normalizeUrl(document.querySelector("link[rel='canonical']")?.getAttribute('href') || window.location.href);
const title = normalize(document.querySelector('main h1')?.textContent || root?.querySelector('h1')?.textContent || document.querySelector("meta[property='og:title']")?.getAttribute('content') || document.title);
const subtitle = normalize(root?.querySelector('h2')?.textContent || document.querySelector("meta[property='og:description'], meta[name='description']")?.getAttribute('content') || '');
const publishedAt = document.querySelector('time')?.getAttribute('datetime') || document.querySelector("meta[property='article:published_time']")?.getAttribute('content') || null;
const authorLink = Array.from(document.querySelectorAll("a[href^='/']")).find((node) => /^\/[A-Za-z0-9_]+(?:\?|$|\/)/.test(node.getAttribute('href') || ''));
const authorHandle = normalize(authorLink?.getAttribute('href')?.split('/')?.filter(Boolean)?.[0] || '');
const authorText = normalize(root?.querySelector("[data-testid='User-Name']")?.textContent || authorLink?.textContent || '');
const imageUrls = unique(Array.from(root.querySelectorAll('img')).map((img) => img.currentSrc || img.getAttribute('src') || '').map(normalizeUrl).filter((src) => /^https?:/i.test(src) && !/profile_images|emoji|abs-0/.test(src)));
const videoUrls = unique([
  ...Array.from(root.querySelectorAll('video')).map((video) => video.currentSrc || video.getAttribute('src') || video.poster || ''),
  ...Array.from(root.querySelectorAll('video source')).map((source) => source.getAttribute('src') || '')
].map(normalizeUrl).filter((src) => /^https?:/i.test(src)));
const externalLinks = unique(Array.from(root.querySelectorAll('a[href]')).map((link) => normalizeUrl(link.getAttribute('href') || link.href)).filter((href) => {
  if (!/^https?:/i.test(href)) return false;
  try {
    const parsed = new URL(href);
    if (parsed.hostname !== window.location.hostname) return true;
    return !/\/article\//i.test(parsed.pathname) && !/\/status\//i.test(parsed.pathname) && !/\/photo\//i.test(parsed.pathname) && !/\/video\//i.test(parsed.pathname);
  } catch {
    return false;
  }
}));
const paragraphs = Array.from(root.querySelectorAll('p')).map((node) => normalize(node.textContent || '')).filter(Boolean);
return {
  article_url: canonicalUrl,
  requested_url: normalizeUrl('{article_url}') || window.location.href,
  title,
  subtitle: subtitle || null,
  author: authorText || null,
  author_handle: authorHandle || null,
  published_at: publishedAt,
  text: paragraphs.join('\n\n') || normalize(root.textContent || ''),
  article_html: root instanceof Element ? root.outerHTML : '',
  image_urls: imageUrls,
  video_urls: videoUrls,
  external_links: externalLinks,
  asset_urls: unique([...imageUrls, ...videoUrls]),
  resolved_via: 'dom'
};
